// // This module shifts the register contents to the right by one bit on each rising edge of the clock signal.
module shift_register(clk, reset, data_out);  

    input  clk;  
    input  reset;  
    output  [2:0] data_out;  
    reg   [2:0] data_out; 
    initial data_out = 0;

    always @(posedge clk)
        begin
            if (reset)
                data_out <= 0;
            else
                data_out <= data_out << 1;
        end  

endmodule
